+function drawWallBanner(ctx: CanvasRenderingContext2D, x: number, y: number, scale: number) {
+  drawBanner(ctx, x, y, 18, 38, '#8b1515', P.gold[3]);
+}
+
+function drawWallShield(ctx: CanvasRenderingContext2D, x: number, y: number, scale: number) {
+  ctx.save();
+  ctx.translate(x, y);
+  ctx.scale(scale, scale);
+  ctx.fillStyle = '#2a4080';
+  ctx.beginPath();
+  ctx.moveTo(10, 2);
+  ctx.lineTo(20, 6);
+  ctx.lineTo(20, 20);
+  ctx.lineTo(15, 26);
+  ctx.lineTo(10, 20);
+  ctx.lineTo(0, 6);
+  ctx.closePath();
+  ctx.fill();
+  ctx.fillStyle = P.gold[3];
+  ctx.fillRect(8, 10, 6, 2);
+  ctx.fillRect(10, 6, 2, 14);
+  ctx.restore();
+}
+
+function drawWallWeaponDisplay(ctx: CanvasRenderingContext2D, x: number, y: number, scale: number) {
+  ctx.save();
+  ctx.translate(x, y);
+  ctx.scale(scale, scale);
+  // Rack frame
+  ctx.fillStyle = '#4a2f1a';
+  ctx.fillRect(2, 4, 24, 20);
+  ctx.strokeStyle = '#3a2510';
+  ctx.lineWidth = 1;
+  for (let i = 4; i < 26; i += 4) {
+    ctx.beginPath();
+    ctx.moveTo(i, 5);
+    ctx.lineTo(i, 22);
+    ctx.stroke();
+  }
+  // Crossbars
+  ctx.fillRect(2, 8, 24, 3);
+  ctx.fillRect(2, 16, 24, 3);
+  ctx.fillStyle = '#3a2510';
+  for (let i = 4; i < 26; i += 6) {
+    ctx.beginPath();
+    ctx.arc(i, 9, 1, 0, Math.PI * 2);
+    ctx.fill();
+    ctx.beginPath();
+    ctx.arc(i, 17, 1, 0, Math.PI * 2);
+    ctx.fill();
+  }
+  // Swords
+  ctx.strokeStyle = '#a0a0a0';
+  ctx.lineWidth = 2;
+  ctx.beginPath();
+  ctx.moveTo(8, 7);
+  ctx.lineTo(8, 21);
+  ctx.stroke();
+  ctx.fillStyle = '#5a5a5a';
+  ctx.fillRect(5, 6, 6, 2);
+  ctx.fillRect(7, 21, 2, 3);
+  ctx.beginPath();
+  ctx.moveTo(16, 7);
+  ctx.lineTo(16, 21);
+  ctx.stroke();
+  ctx.fillRect(13, 6, 6, 2);
+  ctx.fillRect(15, 21, 2, 3);
+  ctx.restore();
+}
+
+function drawWallPainting(ctx: CanvasRenderingContext2D, x: number, y: number, scale: number) {
+  ctx.save();
+  ctx.translate(x, y);
+  ctx.scale(scale, scale);
+  // Frame
+  ctx.fillStyle = P.gold[2];
+  ctx.fillRect(0, 0, 28, 20);
+  ctx.fillStyle = P.gold[3];
+  ctx.fillRect(2, 2, 24, 16);
+  // Painting (simple landscape)
+  ctx.fillStyle = '#3a6b35';
+  ctx.fillRect(4, 6, 20, 10);
+  ctx.fillStyle = '#5080d0';
+  ctx.fillRect(4, 2, 20, 6);
+  ctx.fillStyle = '#f0d75e';
+  ctx.beginPath();
+  ctx.arc(20, 8, 4, 0, Math.PI * 2);
+  ctx.fill();
+  ctx.restore();
+}
+
+function drawWallSconce(ctx: CanvasRenderingContext2D, x: number, y: number, scale: number, frame: number) {
+  ctx.save();
+  ctx.translate(x, y);
+  ctx.scale(scale, scale);
+  // Holder
+  ctx.fillStyle = '#4a2810';
+  ctx.fillRect(10, 10, 8, 6);
+  ctx.fillStyle = '#5c3418';
+  ctx.fillRect(11, 11, 6, 4);
+  // Candle
+  ctx.fillStyle = '#e8dcc4';
+  ctx.fillRect(13, 6, 4, 8);
+  ctx.fillStyle = '#d4c8b0';
+  ctx.fillRect(14, 6, 1, 8);
+  ctx.fillStyle = '#2a2020';
+  ctx.fillRect(14, 4, 1, 3);
+  // Flame flicker
+  const f = Math.sin(frame * 0.25);
+  ctx.fillStyle = '#f0a030';
+  ctx.fillRect(13 + f, 3, 3, 4);
+  ctx.fillStyle = '#ffe880';
+  ctx.fillRect(14, 4, 1, 2);
+  // Glow
+  const grd = ctx.createRadialGradient(15, 5, 0, 15, 5, 10);
+  grd.addColorStop(0, 'rgba(255, 200, 80, 0.08)');
+  grd.addColorStop(1, 'rgba(255, 200, 80, 0)');
+  ctx.fillStyle = grd;
+  ctx.fillRect(5, -5, 20, 20);
+  ctx.restore();
+}
+
+export function drawWallDecoration(
+  ctx: CanvasRenderingContext2D,
+  type: 'banner' | 'shield' | 'weaponDisplay' | 'painting' | 'sconce',
+  x: number,
+  y: number,
+  scale: number,
+  frame: number,
+) {
+  switch (type) {
+    case 'banner': drawWallBanner(ctx, x, y, scale); break;
+    case 'shield': drawWallShield(ctx, x, y, scale); break;
+    case 'weaponDisplay': drawWallWeaponDisplay(ctx, x, y, scale); break;
+    case 'painting': drawWallPainting(ctx, x, y, scale); break;
+    case 'sconce': drawWallSconce(ctx, x, y, scale, frame); break;
+  }
+}
+
